I removed the drag'n'drop code as I found it too application specific. Here is how to handle it yourself.

```JavaScript
var container = stage.viewer.container;
container.dom.addEventListener( 'dragover', function( e ){
    e.stopPropagation();
    e.preventDefault();
    e.dataTransfer.dropEffect = 'copy';
}, false );

container.dom.addEventListener( 'drop', function( e ){
    e.stopPropagation();
    e.preventDefault();
    var file = e.dataTransfer.files[0]
    stage.loadFile( file, { defaultRepresentation: true } );
}, false );
```

